import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Garry Tan「Thin Harness, Fat Skills」五核心概念深度研究","description":"","frontmatter":{"url":"https://github.com/garrytan/gbrain","title":"Garry Tan「Thin Harness, Fat Skills」五核心概念深度研究","author":"Research Compilation (2026-05-23)","date":"2026-05-23T00:00:00.000Z","status":"SUCCESS","sources":["https://www.forbes.com/sites/josipamajic/2026/04/12/the-yc-chief-who-codes-10000-lines-a-day-has-a-simple-secret/","https://github.com/garrytan/gbrain","https://yage.ai/share/thin-harness-fat-skills-en-20260414.html","https://github.com/garrytan/gbrain/blob/master/docs/ethos/THIN_HARNESS_FAT_SKILLS.md"]},"headers":[],"relativePath":"research/ai-articles/40-garry-tan-framework-deep-research.md","filePath":"research/ai-articles/40-garry-tan-framework-deep-research.md","lastUpdated":1779894392000}'),n={name:"research/ai-articles/40-garry-tan-framework-deep-research.md"};function i(s,t,l,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="garry-tan「thin-harness-fat-skills」五核心概念深度研究" tabindex="-1">Garry Tan「Thin Harness, Fat Skills」五核心概念深度研究 <a class="header-anchor" href="#garry-tan「thin-harness-fat-skills」五核心概念深度研究" aria-label="Permalink to &quot;Garry Tan「Thin Harness, Fat Skills」五核心概念深度研究&quot;">​</a></h1><blockquote><p>本文延伸 Forbes 文章（<code>39-forbes-garry-tan-yc-chief-10000-lines.md</code>），蒐集原始發文、實作細節、學術對應。</p></blockquote><hr><h2 id="框架總覽" tabindex="-1">框架總覽 <a class="header-anchor" href="#框架總覽" aria-label="Permalink to &quot;框架總覽&quot;">​</a></h2><p>Garry Tan（YC CEO）主張：</p><blockquote><p>&quot;The 2x people and the 100x people are using the same models. The difference is five concepts that fit on an index card.&quot;</p></blockquote><blockquote><p>&quot;every step in the system is either latent space (model makes a judgment) or deterministic space (program executes reliably)&quot;</p></blockquote><p>框架名稱：<strong>Thin Harness, Fat Skills</strong> 實作：<strong>gbrain</strong>（MIT licensed，2026-04-05 釋出） GitHub：<a href="https://github.com/garrytan/gbrain" target="_blank" rel="noreferrer">https://github.com/garrytan/gbrain</a> 規模：146,646 知識頁面、24,585 人物 profiles、5,339 公司索引、43 個 skill files</p><hr><h2 id="概念一-skill-files" tabindex="-1">概念一：Skill Files <a class="header-anchor" href="#概念一-skill-files" aria-label="Permalink to &quot;概念一：Skill Files&quot;">​</a></h2><h3 id="定義" tabindex="-1">定義 <a class="header-anchor" href="#定義" aria-label="Permalink to &quot;定義&quot;">​</a></h3><p>Skill files 是可重用的 markdown 文件，<strong>編碼流程（process）而非內容（content）</strong>。</p><blockquote><p>&quot;A skill file is a reusable program written in markdown that describes a process of judgment, not a fixed answer.&quot;</p></blockquote><blockquote><p>&quot;The same /investigate skill, pointed at a safety scientist or at FEC filings, produces radically different outputs because the skill describes judgment and the invocation supplies the world.&quot; — Garry Tan, Forbes / X post</p></blockquote><blockquote><p>&quot;Skill files encode process, not content. Think of them as method calls, with markdown as the programming language and human judgment as the runtime.&quot;</p></blockquote><blockquote><p>&quot;The same procedure produces radically different capabilities depending on what you pass in.&quot; — gbrain THIN_HARNESS_FAT_SKILLS.md</p></blockquote><blockquote><p>&quot;Every skill you write is a permanent upgrade to your system. Skills remain stable and benefit automatically when models improve, while the underlying deterministic system remains stable and reliable.&quot;</p></blockquote><h3 id="garry-tan-原始-x-發文" tabindex="-1">Garry Tan 原始 X 發文 <a class="header-anchor" href="#garry-tan-原始-x-發文" aria-label="Permalink to &quot;Garry Tan 原始 X 發文&quot;">​</a></h3><ul><li><a href="https://x.com/garrytan/status/2043566215927328955" target="_blank" rel="noreferrer">&quot;This is the simplest distillation of what I have learned about agentic engineering this year: Push smart fuzzy operations humans do into markdown skills. Fat skills. Push must-be-perfect deterministic operations into code. Fat code. The harness? Keep it thin.&quot;</a></li><li><a href="https://x.com/garrytan/status/2047039391978418569" target="_blank" rel="noreferrer">&quot;Thin Harness Fat Skills Fat Code = THE NEW DRY&quot;</a></li><li><a href="https://x.com/garrytan/status/2047184243164651648" target="_blank" rel="noreferrer">&quot;So far basically fewer fatter skills makes the resolver shorter which itself is less context bloat. Short resolvers are better than long ones&quot;</a></li><li><a href="https://x.com/garrytan/status/2032014570118922347" target="_blank" rel="noreferrer">&quot;I&#39;ve been having such an amazing time with Claude Code I wanted you to be able to have my <em>exact</em> skill setup: Introducing gstack&quot;</a></li><li><a href="https://x.com/garrytan/status/2056915511469023635" target="_blank" rel="noreferrer">&quot;The reason why I release my X articles about AI agents... is that we can have <em>PROCESS POWER</em>, which is the one super powerful specific moat that anyone can create for themselves.&quot;</a></li></ul><h3 id="gstack-開源實作" tabindex="-1">gstack 開源實作 <a class="header-anchor" href="#gstack-開源實作" aria-label="Permalink to &quot;gstack 開源實作&quot;">​</a></h3><p><strong>Repository：</strong> <a href="https://github.com/garrytan/gstack%EF%BC%88MIT%EF%BC%89" target="_blank" rel="noreferrer">https://github.com/garrytan/gstack（MIT）</a><strong>描述：</strong> &quot;Use Garry Tan&#39;s exact Claude Code setup: 23 opinionated tools that serve as CEO, Designer, Eng Manager, Release Manager, Doc Engineer, and QA&quot;</p><p><strong>gstack 核心 skill 範例：</strong></p><table tabindex="0"><thead><tr><th>Skill</th><th>功能</th></tr></thead><tbody><tr><td><code>/investigate</code></td><td>系統性 debug + 根因分析（4 階段：investigate → analyze → hypothesize → implement）</td></tr><tr><td><code>/office-hours</code></td><td>YC 式產品審問（模擬 office hours）</td></tr><tr><td><code>/review</code></td><td>Staff engineer 代碼 review</td></tr><tr><td><code>/plan-eng-review</code></td><td>架構鎖定決策</td></tr><tr><td><code>/plan-ceo-review</code></td><td>產品範疇 review</td></tr><tr><td><code>/design-review</code></td><td>即時視覺稽核</td></tr></tbody></table><p><strong>/investigate Skill 詳細流程（Iron Law: no fixes without root cause）：</strong></p><ol><li>Root Cause Investigation：收集症狀、追蹤 code paths、檢查近期改動</li><li>Pattern Analysis：匹配已知模式（race conditions, null propagation, state corruption）</li><li>Hypothesis Testing：3-strike rule 驗證</li><li>Implementation：只修根因，最小改動</li><li>Verification &amp; Report：重現 bug 確認修復</li></ol><p><strong>Skill 格式：</strong></p><ul><li>YAML frontmatter（metadata）</li><li>Markdown 指令主體</li><li>跨 session 持久化（不同於 one-off prompt）</li><li>可組合（skills can invoke other skills）</li></ul><h3 id="gbrain-實作細節-43-個-skill-分類" tabindex="-1">gbrain 實作細節（43 個 skill 分類） <a class="header-anchor" href="#gbrain-實作細節-43-個-skill-分類" aria-label="Permalink to &quot;gbrain 實作細節（43 個 skill 分類）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>類別</th><th>功能</th></tr></thead><tbody><tr><td>訊號偵測</td><td>每 session 常駐</td></tr><tr><td>內容攝取</td><td>截圖、影片、逐字稿</td></tr><tr><td>思考技能</td><td>腦力激盪、除錯、review</td></tr><tr><td>運營</td><td>任務管理、排程、健康檢查</td></tr><tr><td>身份與存取控制</td><td>安全邊界</td></tr></tbody></table><h3 id="claude-md-精簡路徑" tabindex="-1">CLAUDE.md 精簡路徑 <a class="header-anchor" href="#claude-md-精簡路徑" aria-label="Permalink to &quot;CLAUDE.md 精簡路徑&quot;">​</a></h3><p><strong>Tan 的親身經歷：</strong></p><blockquote><p>&quot;Garry Tan&#39;s CLAUDE.md file was originally 20,000 lines, with every single thing he ran across going in there—every quirk, pattern, and lesson—which he describes as &#39;completely ridiculous.&#39; The model&#39;s attention degraded, and Claude Code advised him to cut it back, with the fix being about 200 lines of pointers to documents, with the resolver loading the right one when it matters.&quot;</p></blockquote><p><strong>結論：</strong> 20,000 行 → 約 <strong>200 行指標</strong>（model attention 在噪音中降解是關鍵原因）</p><p><strong>Context Bloat 量化：</strong></p><blockquote><p>&quot;A Playwright CLI executes browser operations in 100ms, while a Chrome MCP requires 15 seconds for the same screenshot-find-click-wait-read sequence—a 75x performance gap.&quot;</p></blockquote><h3 id="三層架構模型" tabindex="-1">三層架構模型 <a class="header-anchor" href="#三層架構模型" aria-label="Permalink to &quot;三層架構模型&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│         FAT SKILLS（頂層）           │</span></span>
<span class="line"><span>│  markdown procedures 編碼領域知識    │</span></span>
<span class="line"><span>│  90% of the value lives here        │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│         THIN HARNESS（中層）         │</span></span>
<span class="line"><span>│  ~200 行管理：loop/context/安全邊界  │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│         FAT CODE（底層）             │</span></span>
<span class="line"><span>│  Auth, validation, DB, payments     │</span></span>
<span class="line"><span>│  確定性操作，microseconds, 零成本    │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span></code></pre></div><blockquote><p>&quot;Push intelligence UP into skills. Push execution DOWN into deterministic tooling. Keep the harness THIN.&quot;</p></blockquote><h3 id="生產力數據" tabindex="-1">生產力數據 <a class="header-anchor" href="#生產力數據" aria-label="Permalink to &quot;生產力數據&quot;">​</a></h3><ul><li>Garry Tan 每日：<strong>37,000 行程式碼</strong></li><li>每週（part-time YC CEO）：<strong>~10,000 行</strong></li><li>大型 feature（4K+ LOC + 完整測試）：<strong>~1 小時</strong></li><li>效能指標：<strong>~810x vs. 2013 baseline</strong></li></ul><h3 id="gbrain-效能指標" tabindex="-1">gbrain 效能指標 <a class="header-anchor" href="#gbrain-效能指標" aria-label="Permalink to &quot;gbrain 效能指標&quot;">​</a></h3><ul><li>P@5 retrieval accuracy：<strong>97.6%</strong>（LongMemEval 基準，無 LLM query rewriting）</li><li>知識庫規模：146,646 頁、24,585 人物 profiles、5,339 公司索引</li><li>每 session L1 載入：AGENTS.md + RESOLVER.md + master index</li></ul><hr><h2 id="概念二-harness" tabindex="-1">概念二：Harness <a class="header-anchor" href="#概念二-harness" aria-label="Permalink to &quot;概念二：Harness&quot;">​</a></h2><h3 id="定義-1" tabindex="-1">定義 <a class="header-anchor" href="#定義-1" aria-label="Permalink to &quot;定義&quot;">​</a></h3><p>Harness 在迴圈中執行模型，管理 context、讀寫檔案、強制安全邊界。</p><p><strong>反模式（Fat Harness）：</strong></p><ul><li>40+ tool definitions 消耗半個 context window</li><li>God-tools 帶來多秒 MCP round-trip</li><li>REST API wrapper 把每個 endpoint 變一個 tool</li></ul><h3 id="claude-code-洩漏印證-2026-03-31" tabindex="-1">Claude Code 洩漏印證（2026-03-31） <a class="header-anchor" href="#claude-code-洩漏印證-2026-03-31" aria-label="Permalink to &quot;Claude Code 洩漏印證（2026-03-31）&quot;">​</a></h3><h4 id="洩漏事件" tabindex="-1">洩漏事件 <a class="header-anchor" href="#洩漏事件" aria-label="Permalink to &quot;洩漏事件&quot;">​</a></h4><ul><li><strong>日期</strong>：2026-03-31 00:21 UTC</li><li><strong>發現者</strong>：Chaofan Shou（@Fried_rice，Solayer Labs intern）</li><li><strong>原因</strong>：<code>.npmignore</code> 遺漏 <code>*.map</code>，<code>@anthropic-ai/claude-code@2.1.88</code> npm 包夾帶 59.8 MB source map（cli.js.map）</li><li><strong>規模</strong>：512,000+ 行 TypeScript，1,906 個檔案</li><li><strong>Boris Cherny 回應</strong>：「plain developer error」，並補充：「100% of my contributions to Claude Code were written by Claude Code」</li><li><strong>傳播速度</strong>：clean-room rewrite 2 小時達 50,000 GitHub stars（可能是 GitHub 史上增速最快的 repo）</li></ul><h4 id="洩漏揭示的-harness-架構" tabindex="-1">洩漏揭示的 Harness 架構 <a class="header-anchor" href="#洩漏揭示的-harness-架構" aria-label="Permalink to &quot;洩漏揭示的 Harness 架構&quot;">​</a></h4><p><strong>Self-Healing Query Loop（QueryEngine）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統提示構建 → slash-command 預處理 → 多輪工具呼叫迴圈</span></span>
<span class="line"><span>→ context 壓縮（5 種策略）→ 錯誤恢復 → transcript 持久化</span></span></code></pre></div><blockquote><p>&quot;Context compression, message consolidation, and token budget continuation—before surfacing errors to users&quot;</p></blockquote><p><strong>Concurrency-Safe Tool Batching</strong></p><blockquote><p>&quot;Claude issues multiple Read, Glob, and Grep calls in a single turn, and the SDK merges results before the next reasoning step&quot;</p></blockquote><p>使用 async generator 作為 agent loop（非 callback），提供自然 backpressure 與乾淨取消機制。</p><p><strong>模組規模</strong></p><ul><li>46,000 行 query engine（React + Ink terminal rendering）</li><li>40+ 專用 tool plugin</li><li>14 個 cache-break vectors</li><li>23 個 bash security check</li></ul><p><strong>未發佈功能（44 個 feature flags）</strong></p><table tabindex="0"><thead><tr><th>功能</th><th>說明</th></tr></thead><tbody><tr><td><strong>KAIROS</strong></td><td>自主 daemon 模式：筆電關閉時持續背景執行，定期 tick prompt，15 秒/週期 blocking budget</td></tr><tr><td><strong>autoDream</strong></td><td>記憶整合：4 階段（Orient → Gather → Consolidate → Prune），觸發條件：閒置 24h + 最少 5 sessions</td></tr><tr><td><strong>ULTRAPLAN</strong></td><td>遠端規劃，30 分鐘 extended thinking budget</td></tr><tr><td><strong>BUDDY</strong></td><td>Tamagotchi 風格終端伴侶，18 種生物 + 稀有度</td></tr></tbody></table><p><strong>autoDream 四階段：</strong></p><ol><li><strong>Orient</strong>：掃描近期 session logs</li><li><strong>Gather</strong>：提取相關模式與決策</li><li><strong>Consolidate</strong>：壓縮為持久記憶（≤25KB）</li><li><strong>Prune</strong>：移除噪音</li></ol><hr><h2 id="概念三-resolvers" tabindex="-1">概念三：Resolvers <a class="header-anchor" href="#概念三-resolvers" aria-label="Permalink to &quot;概念三：Resolvers&quot;">​</a></h2><h3 id="定義-2" tabindex="-1">定義 <a class="header-anchor" href="#定義-2" aria-label="Permalink to &quot;定義&quot;">​</a></h3><p>Resolver 是 context 的<strong>路由表</strong>：task type X 出現時，載入 document Y。</p><blockquote><p>&quot;Routing lives in skills/RESOLVER.md — the agent reads it once per request, picks the right skill, executes.&quot; — gbrain 文件</p></blockquote><h3 id="三層快取架構" tabindex="-1">三層快取架構 <a class="header-anchor" href="#三層快取架構" aria-label="Permalink to &quot;三層快取架構&quot;">​</a></h3><table tabindex="0"><thead><tr><th>層級</th><th>載入時機</th><th>內容</th></tr></thead><tbody><tr><td><strong>L1（每 session）</strong></td><td>常駐</td><td>AGENTS.md、RESOLVER.md、master index</td></tr><tr><td><strong>L2（on demand）</strong></td><td>按任務類型查詢</td><td>Skills INDEX.md</td></tr><tr><td><strong>L3（on match）</strong></td><td>匹配時</td><td>特定 skill markdown 檔案</td></tr></tbody></table><p>每個 skill 帶 <strong>description field + trigger words</strong>，實現自動 intent 匹配，無需用戶明確指定。</p><h3 id="學術對應" tabindex="-1">學術對應 <a class="header-anchor" href="#學術對應" aria-label="Permalink to &quot;學術對應&quot;">​</a></h3><p><strong>RCR-Router</strong>（arxiv:2508.04903）：</p><blockquote><p>&quot;Dynamically selects semantically relevant memory subsets for each agent based on its role and task stage&quot; 減少 token 使用達 30%</p></blockquote><p><strong>Dynamic Context Loading（DCL）</strong>：按需載入 tool，而非預載所有定義，維持精簡 context window。</p><hr><h2 id="概念四-latent-vs-deterministic" tabindex="-1">概念四：Latent vs Deterministic <a class="header-anchor" href="#概念四-latent-vs-deterministic" aria-label="Permalink to &quot;概念四：Latent vs Deterministic&quot;">​</a></h2><h3 id="定義-tan-原話" tabindex="-1">定義（Tan 原話） <a class="header-anchor" href="#定義-tan-原話" aria-label="Permalink to &quot;定義（Tan 原話）&quot;">​</a></h3><blockquote><p>&quot;every step in the system is either latent space (model makes a judgment) or deterministic space (program executes reliably)&quot;</p></blockquote><h3 id="分工原則" tabindex="-1">分工原則 <a class="header-anchor" href="#分工原則" aria-label="Permalink to &quot;分工原則&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Latent Space（LLM）</th><th>Deterministic Space（程式碼）</th></tr></thead><tbody><tr><td>判斷、合成、分類</td><td>SQL 查詢、算術、組合優化</td></tr><tr><td>模式識別、摘要</td><td>路由、重試邏輯、HTTP status</td></tr><tr><td>創意生成</td><td>驗證、policy check</td></tr></tbody></table><p><strong>反模式：</strong> 強制確定性問題通過 LLM → 輸出「看起來合理但實際錯誤」</p><h3 id="_90-規則-生產實踐" tabindex="-1">~90% 規則（生產實踐） <a class="header-anchor" href="#_90-規則-生產實踐" aria-label="Permalink to &quot;~90% 規則（生產實踐）&quot;">​</a></h3><blockquote><p>&quot;~90% of AI agent work is routing, validation, extraction, and policy checks—tasks that don&#39;t require LLM reasoning&quot;</p></blockquote><p><strong>生產案例：</strong> triage agent 單次成本 $0.31 → $0.04（降 87%，年省 $56,160）</p><h3 id="學術論文支撐" tabindex="-1">學術論文支撐 <a class="header-anchor" href="#學術論文支撐" aria-label="Permalink to &quot;學術論文支撐&quot;">​</a></h3><table tabindex="0"><thead><tr><th>論文</th><th>arXiv</th><th>核心發現</th></tr></thead><tbody><tr><td>Blueprint First, Model Second</td><td>2508.02721</td><td>確定性 Blueprint 引擎 + LLM 只做有邊界子任務</td></tr><tr><td>Replayable Financial Agents</td><td>2601.15322</td><td>LLM 只在真正需要判斷時呼叫，其餘跑確定性程式，μs 級延遲</td></tr><tr><td>Hybrid LLM Routing</td><td>2507.08250</td><td>98.4% 準確率保留，cost 降 67.8%，token 降 66.3%</td></tr><tr><td>RouteLLM</td><td>2406.18665</td><td>動態路由強/弱模型，成本降 2x+，路由遷移性強</td></tr><tr><td>R2-Router</td><td>2602.02823</td><td>使用 GNN + KNN 的資料驅動路由</td></tr><tr><td>Latent State Estimation</td><td>2405.11120</td><td>顯式推斷 latent state 的 agent 任務完成率高 1.6x</td></tr></tbody></table><hr><h2 id="概念五-diarization" tabindex="-1">概念五：Diarization <a class="header-anchor" href="#概念五-diarization" aria-label="Permalink to &quot;概念五：Diarization&quot;">​</a></h2><h3 id="定義-tan-原話-1" tabindex="-1">定義（Tan 原話） <a class="header-anchor" href="#定義-tan-原話-1" aria-label="Permalink to &quot;定義（Tan 原話）&quot;">​</a></h3><blockquote><p>&quot;Diarization: the model reads all materials about a subject and outputs a one-page structured profile... simultaneously reading GitHub commit history, the application, and advisor transcripts to discover that what the founder says and what they build are misaligned—something SQL queries or RAG cannot accomplish alone.&quot;</p></blockquote><p><strong>具體案例：</strong></p><blockquote><p>&quot;a founder claims to be building &#39;Datadog for AI agents,&#39; but 80% of their commits are in the billing module&quot;</p></blockquote><p><strong>YC Startup School 應用：</strong> 6,000 位 founder profiles，每晚執行，自動偵測「說的」與「做的」落差。</p><h3 id="術語說明" tabindex="-1">術語說明 <a class="header-anchor" href="#術語說明" aria-label="Permalink to &quot;術語說明&quot;">​</a></h3><p>⚠️ <strong>「Diarization」是 Tan 的自創術語</strong>。在 NLP/音訊領域，diarization 指說話人辨識（speaker diarization）。Tan 在此賦予全新含義：多源資料融合 → 單頁結構化摘要。</p><h3 id="與-rag-的差異" tabindex="-1">與 RAG 的差異 <a class="header-anchor" href="#與-rag-的差異" aria-label="Permalink to &quot;與 RAG 的差異&quot;">​</a></h3><table tabindex="0"><thead><tr><th>傳統 RAG</th><th>Diarization（Tan 定義）</th></tr></thead><tbody><tr><td>向量檢索相關片段</td><td>讀取主題所有材料</td></tr><tr><td>回答特定問題</td><td>生成跨源整合 profile</td></tr><tr><td>SQL 可部分替代</td><td>SQL/RAG 無法單獨完成</td></tr><tr><td>點查詢</td><td>全面分析後提煉</td></tr></tbody></table><h3 id="學術對應-不同術語" tabindex="-1">學術對應（不同術語） <a class="header-anchor" href="#學術對應-不同術語" aria-label="Permalink to &quot;學術對應（不同術語）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>論文</th><th>核心相似點</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/pdf/2406.14275" target="_blank" rel="noreferrer">Step-Back Profiling</a></td><td>從用戶歷史提煉高層概念 profile，高效記憶管理</td></tr><tr><td><a href="https://arxiv.org/pdf/2409.13093" target="_blank" rel="noreferrer">Guided Profile Generation</a></td><td>中間 guided profile 準確率提升 37% vs 原始 context</td></tr><tr><td><a href="https://arxiv.org/pdf/2510.11952" target="_blank" rel="noreferrer">GRAVITY</a></td><td>profile-grounded 合成偏好，&gt;4% 偏好分提升</td></tr></tbody></table><hr><h2 id="steve-yegge-生產力倍數" tabindex="-1">Steve Yegge 生產力倍數 <a class="header-anchor" href="#steve-yegge-生產力倍數" aria-label="Permalink to &quot;Steve Yegge 生產力倍數&quot;">​</a></h2><blockquote><p>&quot;10x to 100x as productive as engineers using Cursor and chat today, and roughly 1,000x as productive as Googlers were back in 2005.&quot; — Steve Yegge（Tan 引用）</p></blockquote><p><strong>限制（Pragmatic Engineer Podcast）：</strong></p><blockquote><p>&quot;Engineers operating at maximum AI-assisted productivity can sustain it for roughly three hours per day. After that, the cognitive load of directing, reviewing, and integrating AI output becomes overwhelming.&quot;</p></blockquote><hr><h2 id="與-cc-workspace-harness-的對應" tabindex="-1">與 cc-workspace Harness 的對應 <a class="header-anchor" href="#與-cc-workspace-harness-的對應" aria-label="Permalink to &quot;與 cc-workspace Harness 的對應&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tan 的概念</th><th>cc-workspace 實作</th></tr></thead><tbody><tr><td>Thin harness</td><td>CLAUDE.md ≤ 200 行（12-Rule Canon）</td></tr><tr><td>Skill files</td><td><code>.claude/rules/*.md</code> + skills/</td></tr><tr><td>Resolver</td><td>CLAUDE.md <code>@.claude/rules/</code> auto-load</td></tr><tr><td>Latent vs Deterministic</td><td>Rule 5（LLM only for judgment）</td></tr><tr><td>Diarization</td><td><code>/research-hub</code> + <code>overnight-research</code></td></tr><tr><td>KAIROS / autoDream</td><td>hooks（PreToolUse / Stop Hook）</td></tr></tbody></table><hr><h2 id="參考來源" tabindex="-1">參考來源 <a class="header-anchor" href="#參考來源" aria-label="Permalink to &quot;參考來源&quot;">​</a></h2><h3 id="garry-tan-原始資料" tabindex="-1">Garry Tan 原始資料 <a class="header-anchor" href="#garry-tan-原始資料" aria-label="Permalink to &quot;Garry Tan 原始資料&quot;">​</a></h3><ul><li><a href="https://github.com/garrytan/gbrain" target="_blank" rel="noreferrer">gbrain GitHub（MIT）</a></li><li><a href="https://github.com/garrytan/gbrain/blob/master/docs/ethos/THIN_HARNESS_FAT_SKILLS.md" target="_blank" rel="noreferrer">THIN_HARNESS_FAT_SKILLS.md</a></li><li><a href="https://github.com/garrytan/gbrain/blob/master/skills/RESOLVER.md" target="_blank" rel="noreferrer">RESOLVER.md</a></li><li><a href="https://yage.ai/share/thin-harness-fat-skills-en-20260414.html" target="_blank" rel="noreferrer">Thin Harness, Fat Skills — 英文解析</a></li><li><a href="https://moonsat.medium.com/thin-harness-fat-skills-a3dd6d2fe2af" target="_blank" rel="noreferrer">Medium 解析</a></li></ul><h3 id="claude-code-洩漏分析" tabindex="-1">Claude Code 洩漏分析 <a class="header-anchor" href="#claude-code-洩漏分析" aria-label="Permalink to &quot;Claude Code 洩漏分析&quot;">​</a></h3><ul><li><a href="https://layer5.io/blog/engineering/the-claude-code-source-leak-512000-lines-a-missing-npmignore-and-the-fastest-growing-repo-in-github-history/" target="_blank" rel="noreferrer">Layer5 工程分析</a></li><li><a href="https://www.deeplearning.ai/the-batch/claude-codes-source-code-leaked-exposing-potential-future-features-kairos-and-autodream/" target="_blank" rel="noreferrer">DeepLearning.AI The Batch（KAIROS/autoDream）</a></li><li><a href="https://www.infoq.com/news/2026/04/claude-code-source-leak/" target="_blank" rel="noreferrer">InfoQ 詳細分析</a></li><li><a href="https://x.com/Fried_rice/status/2038894956459290963" target="_blank" rel="noreferrer">Chaofan Shou 原始 X 貼文</a></li><li><a href="https://www.zscaler.com/blogs/security-research/anthropic-claude-code-leak" target="_blank" rel="noreferrer">Zscaler ThreatLabz 安全分析</a></li></ul><h3 id="學術論文" tabindex="-1">學術論文 <a class="header-anchor" href="#學術論文" aria-label="Permalink to &quot;學術論文&quot;">​</a></h3><ul><li><a href="https://arxiv.org/pdf/2508.02721" target="_blank" rel="noreferrer">Blueprint First, Model Second (arXiv:2508.02721)</a></li><li><a href="https://arxiv.org/pdf/2601.15322" target="_blank" rel="noreferrer">Replayable Financial Agents (arXiv:2601.15322)</a></li><li><a href="https://arxiv.org/abs/2507.08250" target="_blank" rel="noreferrer">Hybrid LLM Routing (arXiv:2507.08250)</a></li><li><a href="https://arxiv.org/abs/2406.18665" target="_blank" rel="noreferrer">RouteLLM (arXiv:2406.18665)</a></li><li><a href="https://arxiv.org/pdf/2602.02823" target="_blank" rel="noreferrer">R2-Router (arXiv:2602.02823)</a></li><li><a href="https://arxiv.org/pdf/2405.11120" target="_blank" rel="noreferrer">Latent State Estimation (arXiv:2405.11120)</a></li><li><a href="https://arxiv.org/abs/2508.04903" target="_blank" rel="noreferrer">RCR-Router (arXiv:2508.04903)</a></li><li><a href="https://arxiv.org/pdf/2406.14275" target="_blank" rel="noreferrer">Step-Back Profiling (arXiv:2406.14275)</a></li><li><a href="https://arxiv.org/pdf/2409.13093" target="_blank" rel="noreferrer">Guided Profile Generation (arXiv:2409.13093)</a></li><li><a href="https://arxiv.org/pdf/2510.11952" target="_blank" rel="noreferrer">GRAVITY (arXiv:2510.11952)</a></li></ul>`,117)])])}const g=e(n,[["render",i]]);export{p as __pageData,g as default};
